Code Good:
@HiltViewModel
class ProductViewModel @Inject constructor(
    private val repository: ProductRepository
) : ViewModel() {
    private val _state = MutableStateFlow(ProductUiState())
    val state: StateFlow<ProductUiState> = _state.asStateFlow()

    fun loadProducts() {
        viewModelScope.launch {
            _state.update { it.copy(isLoading = true) }
            repository.getProducts().fold(
                onSuccess = { products -> _state.update { it.copy(products = products, isLoading = false) } },
                onFailure = { error -> _state.update { it.copy(error = error.message, isLoading = false) } }
            )
        }
    }
}

@Composable
fun ProductScreen(viewModel: ProductViewModel = hiltViewModel()) {
    val state by viewModel.state.collectAsStateWithLifecycle()
}

