Code Good:
@Composable
fun ProductList(products: List<Product>, onProductClick: (Product) -> Unit) {
    val sortedProducts by remember(products) {
        derivedStateOf { products.sortedBy { it.name } }
    }

    LazyColumn {
        items(sortedProducts, key = { it.id }) { product ->
            ProductCard(
                product = product,
                onClick = { onProductClick(product) }
            )
        }
    }
}

